                       f'ETL_ERROR: {field_name} must be a string', path)
    trimmed = value.strip()
    if not trimmed:
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       f'ETL_ERROR: {field_name} cannot be empty', path)
    return trimmed


